  methods: {
    insertSpaces(text) {
      text = text.replace(/([a-z])([A-Z])/g, '$1 $2');
      text = text.replace(/([A-Z])([A-Z][a-z])/g, '$1 $2');
      return text;
    },
    kebabCase(text) {
      text = text.replace(/([a-z])([A-Z])/g, "$1-$2");
      text = text.replace(/[\s_]+/g, '-').toLowerCase();
      return text;
    },
    camelize(text) {
      return text.replace(/(?:^\w|[A-Z]|\b\w)/g, function(word, index) {
        return index === 0 ? word.toLowerCase() : word.toUpperCase();
      }).replace(/\s+/g, '');
    },
    paginate() {
      this.data = [];
      this.totalPages = Math.ceil(this.total / this.itemsPerPage);
    },
    onPageChange(page) {
      this.loading = true;
      this.pageNumber = page;

      var filterInfo = "";

      for (let i = 0; i < this.selectedFilters.length; i++) {
        if (this.selectedFilters[i]['checked']) {
          var key = this.selectedFilters[i]['title'];
          var value = this.selectedFilters[i]['value'];

          if(i > 0) {
            filterInfo += ', '; 
          }

          if (this.selectedFilters[i]['type'] == 'boolean'){
            filterInfo += '"' + key + '": ' + value + '';
          } else {
            filterInfo += '"' + key + '": "' + value + '"';
          }

          this.filterValue += this.selectedFilters[i]['value'];
        }
      }

      if (this.filterValue.length == 0) {
        this.filterData = "";
      } else {
        this.filterData = '{"pageSize": '+ this.pageSize + ', "pageNumber": ' + this.pageNumber + ', ' + filterInfo + '}'
      }

      if (!this.filterData) {
        this.searchWithoutFilter();
      } else {
        this.searchWithFilter();
      }
    },
    // handleFilterSetting() {
    //   this.isFilterSettingActive = !this.isFilterSettingActive;
    // },
    closeFilterList() {
      this.active = false;
    },
    checkedFilter(filter) {
      if (filter['checked'] == true) {
        this.selectedFilters.push(filter)
      } else {
        for (var i = this.selectedFilters.length - 1; i >= 0; --i) {
          if (this.selectedFilters[i].title == filter['title']) {
            this.selectedFilters.splice(i,1);
          }
        }
        // this.selectedFilters.splice(this.selectedFilters.indexOf(filter), 1);
      }
    },
    submitStoreCode() {},
    submitFilters() {
      this.loading = true;

      var filterInfo = "";

      for (let i = 0; i < this.selectedFilters.length; i++) {
        if (this.selectedFilters[i]['checked']) {
          var key = this.selectedFilters[i]['title'];
          var value = this.selectedFilters[i]['value'];

          if(i > 0) {
            filterInfo += ', '; 
          }

          if (this.selectedFilters[i]['type'] == 'boolean'){
            filterInfo += '"' + key + '": ' + value + '';
          } else {
            filterInfo += '"' + key + '": "' + value + '"';
          }

          this.filterValue += this.selectedFilters[i]['value'];
        }
      }

      if (this.selectedFilters.length == 0) {
        this.filterData = "";
      } else {
        this.pageNumber = 1;
        this.filterData = '{"pageSize": '+ this.pageSize + ', "pageNumber": ' + this.pageNumber + ', ' + filterInfo + '}'
      }

      if (!this.filterData) {
        this.searchWithoutFilter();
      } else {
        this.searchWithFilter();
      }
    },
    searchWithoutFilter() {
      axios
        .post(
          url,
          {
            pageSize: this.pageSize,
            pageNumber: this.pageNumber
          },
          {
            headers: {
              "x-store": this.storeCode,
            },
          }
        )
        .then(response => {
          this.data = response.data;
          this.count = response.data.count;
          this.pageTotal = response.data.pageTotal;
        })
        .catch(error => {
          console.log(error)
          this.errored = true
        })
        .finally(() => this.loading = false)
    },
    searchWithFilter() {
      axios
        .post(
          url,
          this.filterData,
          {
            headers: {
              "x-store": this.storeCode,
              'Content-Type': 'application/json'
            },
          }
        )
        .then((response) => {
          this.data = response.data;
          this.count = response.data.count;
          this.pageTotal = response.data.pageTotal;
