<template>
  <div class="wrapper">
    <div class="flex align-center gap-10">
      <ul class="pagination">
        <!-- <li
      class="pagination-item"
    >
      <button
        type="button"
        @click="onClickFirstPage"
        :disabled="isInFirstPage"
        aria-label="Go to first page"
      >
        First
      </button>
    </li> -->

        <li v-for="page in pages" :key="page" class="pagination-item">
          <button type="button"
                  @click="onClickPage(page.name)"
                  :disabled="page.isDisabled"
                  :class="{ active: isPageActive(page.name) }"
                  :aria-label="`Go to page number ${page.name}`">
            {{ page.name }}
          </button>
        </li>

        <!-- <li class="pagination-item">
      <button
        type="button"
        @click="onClickLastPage"
        :disabled="isInLastPage"
        aria-label="Go to last page"
      >
        Last
      </button>
    </li> -->
      </ul>
      <p>
        <span v-if="!isInLastPage">{{ perPage * pageNumber }}</span>
        <span v-if="isInLastPage">{{ total }}</span> of {{ total }} records
      </p>
    </div>

    <div class="flex align-center gap-10">
      <button class="page-btn"
              type="button"
              @click="onClickPreviousPage"
              :disabled="isInFirstPage"
              :class="pageNumber > 1 ? '' : 'disabled'"
              aria-label="Go to previous page">
        <fa icon="angle-left"></fa>
      </button>

      <button class="page-btn"
              type="button"
              @click="onClickNextPage"
              :disabled="isInLastPage"
              :class="totalPages > 1 && pageNumber < totalPages ? '' : 'disabled'"
              aria-label="Go to next page">
        <fa icon="angle-right"></fa>
      </button>
    </div>

  </div>
</template>

<script>
export default {
  name: "pagination",
  props: {
    maxVisibleButtons: {
      type: Number,
      required: false,
      default: 5,
    },
    totalPages: {
      type: Number,
      required: true,
    },
    total: {
      type: Number,
      required: true,
    },
    perPage: {
      type: Number,
      required: true,
    },
    pageNumber: {
      type: Number,
      required: true,
    },
  },
  computed: {
    startPage() {
      if (this.pageNumber === 1) {
        return 1;
      }
      if (this.pageNumber === this.totalPages) {
        return this.totalPages - this.maxVisibleButtons + 1;
      }
      return this.pageNumber - 1;
    },
    endPage() {
      return Math.min(
        this.startPage + this.maxVisibleButtons - 1,
        this.totalPages
      );
    },
    pages() {
      const range = [];

      for (let i = this.startPage; i <= this.endPage; i += 1) {
        range.push({
          name: i,
          isDisabled: i === this.pageNumber,
        });
      }
      return range;
    },
    isInFirstPage() {
      return this.pageNumber === 1;
    },
    isInLastPage() {
      return this.pageNumber === this.totalPages;
    },
  },
  methods: {
    // onClickFirstPage() {
    //   this.$emit('pagechanged', 1);
    // },
    onClickPreviousPage() {
      this.$emit("pageChanged", this.pageNumber - 1);
    },
    onClickPage(page) {
      this.$emit("pageChanged", page);
    },
    onClickNextPage() {
      this.$emit("pageChanged", this.pageNumber + 1);
    },
    // onClickLastPage() {
    //   this.$emit('pagechanged', this.totalPages);
    // },
    isPageActive(page) {
      return this.pageNumber === page;
    },
  },
};
</script>

<style scoped>
.wrapper {
  display: flex;
  justify-content: space-between;
  margin: 20px 0;
}
.pagination {
  list-style-type: none;
}

.pagination-item {
  display: inline-block;
}
.pagination-item button {
  background-color: #fff;
  width: 28px;
  height: 28px;
  border: 1px solid #ddd;
  border-radius: 50%;
  margin-right: 5px;
  box-shadow: 0 1px 6px 0 rgba(32, 33, 36, 0.28);
}
.active {
  background-color: #2ba993!important;
  color: #ffffff;
  border: 1px solid #2ba993!important;
}
.page-btn {
  color: #2ba993;
  background-color: #fff;
  width: 45px;
  height: 28px;
  border: 1px solid #ddd;
  border-radius: 25px;
}
.disabled {
  pointer-events:none;
  color:#aaa;
  background:#F5F5F5;
}
</style>
